import{_ as t,o as r,c as i,ag as a}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt4102.jpg",s="/images/lekt4103.jpg",u="/images/lekt4106.jpg",d="/images/lekt4107.jpg",o="/images/lekt4108.jpg",l="/images/lekt4105.jpg",h="/images/lekt4104.jpg",p="/images/lekt4109.jpg",b="/images/lekt4110.jpg",m="/images/lekt4111.jpg",P=JSON.parse('{"title":"Lektion 41","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion41.md","filePath":"lektionen/lektion41.md"}'),c={name:"lektionen/lektion41.md"};function f(g,e,k,q,w,v){return r(),i("div",null,[...e[0]||(e[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-41" tabindex="-1">Lektion 41 <a class="header-anchor" href="#lektion-41" aria-label="Permalink to &quot;Lektion 41&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>41.1. सुभाषिते  (zwei Sprichwörter)</li><li>41.2. Weitere कृत्-Bildungen auf -a <ul><li>41.2.1. Partizip Präsens (लडादेशः) Ā, Partizip Präsens (लडादेशः) Passiv, Partizip Futur (ऌडादेशः) Ā <ul><li>41.2.1.1. Thematische Präsensstämme, Passiv und Futur</li><li>41.2.1.2. Athematische Präsensklassen</li></ul></li><li>41.2.2. &quot;Partizip&quot; der passiven Notwendigkeit (Gerundivum) (कृत्य) <ul><li>41.2.2.1. Das Suffix -तव्य / -तव्या</li><li>41.2.2.2. Das Suffix -अनीय / -अनीया</li><li>41.2.2.3. Das Suffix -य / -या</li><li>41.2.2.4. Das Suffix -त्य / त्या (statt -य / -या)</li></ul></li><li>41.2.3. Syntaktisches zum &quot;Partizip&quot; der passiven Notwendigkeit (Gerundivum) (कृत्य)</li><li>41.2.4. Unterschiede im Gebrauch der Gerundiv-Suffixe</li><li>41.2.5. Keine Verbindung mit सु- und दुस्-</li></ul></li><li>41.3. Wortliste</li><li>41.4. Übung</li></ul><h2 id="_41-1-सुभाषिते-zwei-sprichworter" tabindex="-1">41.1. सुभाषिते  (zwei Sprichwörter) <a class="header-anchor" href="#_41-1-सुभाषिते-zwei-sprichworter" aria-label="Permalink to &quot;41.1. सुभाषिते  (zwei Sprichwörter)&quot;">​</a></h2><blockquote><p>पुस्तकस्था च या विद्या<br> परहस्ते च यद्धनम् ।<br> कार्यकाले समुत्पन्ने<br> न सा विद्या न तद्धनम् ॥१॥</p></blockquote><p>Erklärung: पर &quot;anderer&quot;</p><p><img src="'+n+'" alt=""><br> Abb.: पुस्तकस्था च या विद्या ...<br> Bhubaneswar = ଭୁବନେଶ୍ବର<br> [Bildquelle: souravdas. -- <a href="http://www.flickr.com/photos/souravdas/2786531408/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/souravdas/2786531408/</a>. -- Zugriff am 2009-01-02. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><blockquote><p>उपदेशो हि मूर्खाणां<br> प्रकोपाय न शान्तये ।<br> पयःपानं भुजङ्गानां<br> केवलं विषवर्धनम् ॥२॥</p></blockquote><p>Erklärung: पयस् n. = दुग्धम्</p><h2 id="_41-2-weitere-कृत्-bildungen-auf-a" tabindex="-1">41.2. Weitere कृत्-Bildungen auf -a <a class="header-anchor" href="#_41-2-weitere-कृत्-bildungen-auf-a" aria-label="Permalink to &quot;41.2. Weitere कृत्-Bildungen auf -a&quot;">​</a></h2><h3 id="_41-2-1-partizip-prasens-लडादेशः-a-partizip-prasens-लडादेशः-passiv-partizip-futur-ऌडादेशः-a" tabindex="-1">41.2.1. Partizip Präsens (लडादेशः) Ā, Partizip Präsens (लडादेशः) Passiv, Partizip Futur (ऌडादेशः) Ā <a class="header-anchor" href="#_41-2-1-partizip-prasens-लडादेशः-a-partizip-prasens-लडादेशः-passiv-partizip-futur-ऌडादेशः-a" aria-label="Permalink to &quot;41.2.1. Partizip Präsens (लडादेशः) Ā, Partizip Präsens (लडादेशः) Passiv, Partizip Futur (ऌडादेशः) Ā&quot;">​</a></h3><h4 id="_41-2-1-1-thematische-prasensstamme-passiv-und-futur" tabindex="-1">41.2.1.1. Thematische Präsensstämme, Passiv und Futur <a class="header-anchor" href="#_41-2-1-1-thematische-prasensstamme-passiv-und-futur" aria-label="Permalink to &quot;41.2.1.1. Thematische Präsensstämme, Passiv und Futur&quot;">​</a></h4><p>Bildung:</p><p>Präsensstamm / Passivstamm / Futurstamm + -māna (fem. mānā)</p><p>Beispiele:</p><p>यज् 1U, Part.Präs.Ā यजमान 3 &quot;jemand, der im eignen Interesse mit einem Opfer verehrt = Opferherr&quot;</p><p>मन् 4Ā, Part.Präs.Ā  मन्यमान 3 &quot;ein denkender&quot;</p><p>कृ 8U, Part.Präs.Passiv क्रियमाण 3 &quot;etwas, das getan wird&quot;</p><p>दा 3U, Part.Fut.Ā दास्यमान 3 &quot;jemand, der im eignen Interesse geben wird&quot;</p><h4 id="_41-2-1-2-athematische-prasensklassen" tabindex="-1">41.2.1.2. Athematische Präsensklassen <a class="header-anchor" href="#_41-2-1-2-athematische-prasensklassen" aria-label="Permalink to &quot;41.2.1.2. Athematische Präsensklassen&quot;">​</a></h4><p>Bildung:</p><p>Schwacher Präsensstamm (in der Form, die er vor der Endung -ate der 3.pl.Ā hat) + -āna (fem. -ānā)</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th></th><th>Pert.Präs.Ā</th></tr></thead><tbody><tr><td>द्विष् 2U</td><td></td></tr><tr><td>द्वि्षाण</td><td></td></tr></tbody></table><p>| | हु 3P |</p><p>&lt;जुह्वान&gt;<br> ju-hu + āna</p><p>| | सु 5U |</p><p>सुन्वान<br> su-nu + āna</p><p>| | रुध् |</p><p>रुन्धान<br> ru-n-dh-āna</p><p>| | तन् |</p><p>तन्वान<br> tan-u + āna</p><p>| | क्री |</p><p>क्रीणान<br> krī + n-āna</p><p>|</p></blockquote><h3 id="_41-2-2-partizip-der-passiven-notwendigkeit-gerundivum-कृत्य" tabindex="-1">41.2.2. &quot;Partizip&quot; der passiven Notwendigkeit (Gerundivum) (कृत्य) <a class="header-anchor" href="#_41-2-2-partizip-der-passiven-notwendigkeit-gerundivum-कृत्य" aria-label="Permalink to &quot;41.2.2. &quot;Partizip&quot; der passiven Notwendigkeit (Gerundivum) (कृत्य)&quot;">​</a></h3><p>Um die passive Notwendigkeit auszudrücken (&quot;was getan werden muss/soll&quot;), kann man Adjektive aus Wurzeln und abgeleiteten Verbalstämmen wahlweise mit folgenden Suffixen bilden:</p><ul><li>-तव्य (fem. -तव्या)</li><li>-अनीय (fem. -अनिईया)</li><li>-य (fem. -या)</li><li>-त्य (fem. -त्या) (statt -य/-या)</li></ul><h4 id="_41-2-2-1-das-suffix-तव्य-तव्या" tabindex="-1">41.2.2.1. Das Suffix -तव्य / -तव्या <a class="header-anchor" href="#_41-2-2-1-das-suffix-तव्य-तव्या" aria-label="Permalink to &quot;41.2.2.1. Das Suffix -तव्य / -तव्या&quot;">​</a></h4><p>Das Suffix -तव्य / -तव्या wird an Wurzeln und abgeleitete Verbalstämme (z.B. Kausativ) auf dieselbe Weise angefügt wie das Infinitivsuffix -तुम् (s. <a href="./lektion23">Lektion 23</a>), d.h.</p><ul><li>hochstufige Wurzel + तव्य</li></ul><p>oder</p><ul><li>hochstufige Wurzel + -i- + तव्य</li></ul><p>Im Kausativ:</p><ul><li>Kasusativstamm auf -ay + -i- + तव्य</li></ul><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>जि 1P</th><th>जेतव्य 3</th><th>&quot;jemand, der besiegt werden muss; ein zu  besiegender&quot;</th></tr></thead><tbody><tr><td>वृत् 1Ā</td><td>वर्तितव्य 3</td><td>&quot;das, wo man sich befinden soll&quot;</td></tr><tr><td>बुध् Kaus.</td><td>बोधयितव्य</td><td>&quot;jemand, der geweckt werden soll; ein zu erweckender&quot;</td></tr></tbody></table></blockquote><h4 id="_41-2-2-2-das-suffix-अनीय-अनीया" tabindex="-1">41.2.2.2. Das Suffix -अनीय / -अनीया <a class="header-anchor" href="#_41-2-2-2-das-suffix-अनीय-अनीया" aria-label="Permalink to &quot;41.2.2.2. Das Suffix -अनीय / -अनीया&quot;">​</a></h4><p>Bildung:</p><p>Hochstufige Wurzel + -अनीय / -अनीया</p><p>Kausativ und 10. Präsensklasse:</p><p>Wurzel, wie sie im Kausativstamm erscheint, ohne -aya- + -अनीय / -अनीया</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>दा 3U</th><th>दानीय 3</th><th>&quot;zu gebendes; was gegeben werden muss&quot;</th></tr></thead><tbody><tr><td>जि 1P</td><td>जयनीय 3</td><td>&quot;zu besiegender&quot;</td></tr><tr><td>कृ 8U</td><td>करणीय 3</td><td>&quot;zu tuendes&quot;</td></tr><tr><td>दृश्</td><td>दर्शनीय 3</td><td>&quot;was man sehen muss; sehenswertes&quot;</td></tr><tr><td>बुध् Kaus.</td><td>बोधनीय 3</td><td></td></tr><tr><td>bodh-aya - aya + -anīya</td><td>&quot;ein zu weckender&quot;</td><td></td></tr><tr><td>दा Kaus.</td><td>दापनीय 3</td><td></td></tr><tr><td>dā-paya - aya + -anīya</td><td>&quot;was man geben lassen muss&quot;</td><td></td></tr></tbody></table></blockquote><h4 id="_41-2-2-3-das-suffix-य-या" tabindex="-1">41.2.2.3. Das Suffix -य / -या <a class="header-anchor" href="#_41-2-2-3-das-suffix-य-या" aria-label="Permalink to &quot;41.2.2.3. Das Suffix -य / -या&quot;">​</a></h4><p>Bildung:</p><p>Wurzel (in Tief-, Hoch- oder Dehnstufe) + -य</p><p>Die genauen Regeln siehe bei Kielhorn, Grammatik der Sanskrit-Sprache, S. 195 - 197!</p><p>Behandlung auslautender Vokale:</p><p>1. Wurzeln auf -ā bilden dieses Gerundiv auf -eya</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>ज्ञा 9U</th><th>ज्ञेय 3</th><th>&quot;zu wissendes; was erkannt werden muss&quot;</th></tr></thead><tbody><tr><td>दा 3U</td><td>देय 3</td><td>&quot;was gegeben werden muss&quot;</td></tr></tbody></table></blockquote><p>2. Wurzeln auf -i /-ī / -u / -ū /-ṛ haben in der Regel Hoch- oder Dehnstufe, es sei denn sie gehören zu denjenigen Wurzeln auf -i / -u /-ṛ, die ein Gerundiv mit dem Suffix -त्य (fem. -त्या) bilden (Liste dieser Wurzeln bei Kielhorn, Grammatik §537).</p><p>Beispiel:</p><blockquote><table tabindex="0"><thead><tr><th>स्मृ 1P</th><th>स्मर्य 3</th><th>&quot;woran man sich erinnern muss&quot;</th></tr></thead></table></blockquote><p>2a. Wurzeln auf -i/-ī haben Hochstufe</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>विक्री 9Ā</th><th>विक्रेय 3</th><th>&quot;zu verkaufen; verkäuflich&quot;</th></tr></thead><tbody><tr><td>नी 1U</td><td>नेय 3</td><td>&quot;zu führender&quot;</td></tr></tbody></table></blockquote><p><img src="'+s+'" alt=""><br> Abb.: विक्रेयाणि पुष्पानि<br> महाराष्ट्रे<br> [Bildquelle: Harshad Sharma. -- <a href="http://www.flickr.com/photos/harshadsharma/57609357/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/harshadsharma/57609357/</a>. -- Zugriff am 2009-01-03. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>2b. Wurzeln auf -u /-ū ersetzen das hochstufige -o vor dem -ya durch -av, das dehnstufige -au durch -āv. Dehnstufige Bildung bedeutet in diesem Fall Notwendigkeit.</p><p>Beispiel:</p><blockquote><table tabindex="0"><thead><tr><th>स्तु 2U</th><th>स्तव्य 3</th><th>&quot;was gepriesen werden soll&quot;</th></tr></thead><tbody><tr><td></td><td>स्ताव्य 3</td><td>&quot;was notwendig gepriesen werden muss&quot;</td></tr></tbody></table></blockquote><p>Beispiele für konsonantisch auslautende Wurzeln (Regeln s. Kielhorn, Grammatik § 533ff.):</p><p>Tiefstufige Bildung:</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>दृश्</th><th>दृश्य 3</th><th>&quot;sehenswert&quot;</th></tr></thead><tbody><tr><td>शास् 2P</td><td>शिष्य 3</td><td>&quot;jemand, der zu belehren ist = Schüler&quot;</td></tr></tbody></table></blockquote><p><img src="'+u+'" alt=""><br> Abb.: दृश्यो मन्दिरः<br> Bahá&#39;í House of Worship, Delhi<br> [Bildquelle: Ray KOH. -- <a href="http://www.flickr.com/photos/raykoh/1497654220/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/raykoh/1497654220/</a>. -- Zugriff am 2009-01-03. --  <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>Hochstufige Bildung:</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>द्विष् 2U</th><th>द्वेष्य 3</th><th>&quot;zu hassender = Feind&quot;</th></tr></thead><tbody><tr><td>भिद् 7U</td><td>भेद्य 3</td><td>&quot;zu spaltender&quot;</td></tr></tbody></table></blockquote><p>Kausative und Verben der 10. Präsensklasse (चुरादि)</p><p>Bildung:</p><p>Kausativ-/Präsensstamm ohne -aya- + -य</p><p>Beispiel:</p><blockquote><p>| मन् Kausativ1 | मान्य 3<br> mān-aya - aya + ya</p><p>| &quot;zu ehrender, hochverehrter&quot; | | --- | --- | --- |</p><p>1 eigentl. Denominativ zu मान</p></blockquote><p><img src="'+d+'" alt=""><br> Abb.: मान्यः<br> Dr. Bhimrao Ramji Ambedkar  = डॊ.भीमराव रामजी आंबेडकर (1891 - 1956)<br> [Bildquelle: Wikipedia. Public domain]</p><h4 id="_41-2-2-4-das-suffix-त्य-त्या-statt-य-या" tabindex="-1">41.2.2.4. Das Suffix -त्य / त्या (statt -य / -या) <a class="header-anchor" href="#_41-2-2-4-das-suffix-त्य-त्या-statt-य-या" aria-label="Permalink to &quot;41.2.2.4. Das Suffix -त्य / त्या (statt -य / -या)&quot;">​</a></h4><p>Liste der Wurzeln auf -i / -u /-ṛ, die ein Gerundiv statt mit -य / -या mit dem Suffix -त्य (fem. -त्या) bilden, bei Kielhorn, Grammatik §537.</p><p>Bildung:</p><p>tiefstufige Wurzel + -त्य् / -त्या</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>इ 2P</th><th>इत्य 3</th><th>&quot;zu gehender&quot;</th></tr></thead><tbody><tr><td>श्रु 5P</td><td>श्रुत्य 3</td><td>&quot;zu hörender&quot;</td></tr><tr><td>कृ 8U</td><td>कृत्य 3</td><td>&quot;zu tuender&quot;</td></tr></tbody></table></blockquote><h3 id="_41-2-3-syntaktisches-zum-partizip-der-passiven-notwendigkeit-gerundivum-कृत्य" tabindex="-1">41.2.3. Syntaktisches zum &quot;Partizip&quot; der passiven Notwendigkeit (Gerundivum) (कृत्य) <a class="header-anchor" href="#_41-2-3-syntaktisches-zum-partizip-der-passiven-notwendigkeit-gerundivum-कृत्य" aria-label="Permalink to &quot;41.2.3. Syntaktisches zum &quot;Partizip&quot; der passiven Notwendigkeit (Gerundivum) (कृत्य)&quot;">​</a></h3><p>Das Gerundiv kann atttributiv verwendet werden:</p><blockquote><p>दर्शनीयं बगरम् = &quot;eine Stadt, die man sehen muss; eine sehenswerte Stadt&quot;</p></blockquote><p>Das Gerundiv kann auch als Prädikatsnomen in Sätzen mit Passivkonstruktion verwendet werden, die eine Verpflichtung oder einen Befehl ausdrücken (mit न ein Verbot, eine Unmöglichkeit):</p><blockquote><p>काशी द्विजैर्द्रष्टवया = &quot;Zweimalgeborene müssen Benares sehen&quot;</p></blockquote><p><img src="'+o+'" alt=""><br> Abb.: दर्शनीयं नगरं काशी<br> काशी द्विजैर्द्रष्टवया<br> मणिकर्णिका घाट, 1922<br> [Bildquelle LoC/Wikipedia. Public domain]</p><h3 id="_41-2-4-unterschiede-im-gebrauch-der-gerundiv-suffixe" tabindex="-1">41.2.4. Unterschiede im Gebrauch der Gerundiv-Suffixe <a class="header-anchor" href="#_41-2-4-unterschiede-im-gebrauch-der-gerundiv-suffixe" aria-label="Permalink to &quot;41.2.4. Unterschiede im Gebrauch der Gerundiv-Suffixe&quot;">​</a></h3><p>Weitgehend überschneidet sich der Gebrauch dieser Suffixe</p><ul><li>-तव्य (fem. -तव्या): drückt immer eine Notwendigkeit aus und wird bevorzugt prädikativ gebraucht (seltener attributiv). Bildungen mit diesem Suffix sollen nicht in Nominalkomposita verwendet werden.</li><li>-अनीय (fem. -अनिईया) und -य (fem. -या) / -त्य (fem. -त्या) (statt -य/-या) können eine weitere Bedeutung haben (bes. -य) im Sinne des deutschen &quot;-wert&quot; (z.B. &quot;sehenswert&quot;) oder nur einer Möglichkeit &quot;-bar&quot; (दृश्य &quot;sichtbar&quot;). Bildungen mit diesen Suffixen können mit अ-/-अन्- verneint werden (nicht aber Bildungen mit -तव्य) und es gibt तत्पुरुष als deren Hintergleid sie vorkommen</li></ul><h3 id="_41-2-5-keine-verbindung-mit-सु-und-दुस्" tabindex="-1">41.2.5. Keine Verbindung mit सु- und दुस्- <a class="header-anchor" href="#_41-2-5-keine-verbindung-mit-सु-und-दुस्" aria-label="Permalink to &quot;41.2.5. Keine Verbindung mit सु- und दुस्-&quot;">​</a></h3><p>Mit सु- und दुस्- in der Bedeutung &quot;leicht&quot; bzw. &quot;schwer&quot; dürfen Gerundive nicht verbunden werden. Statt dessen stehen तत्पुरुष vom Typ सुकर 3 (&quot;leicht zu tun&quot;) (s. <a href="./lektion18">Lektion 18</a>)</p><h2 id="_41-3-wortliste" tabindex="-1">41.3. Wortliste <a class="header-anchor" href="#_41-3-wortliste" aria-label="Permalink to &quot;41.3. Wortliste&quot;">​</a></h2><p>मूर्ख m = मूढ</p><p>भुजङ्ग m.: Schlange</p><p><img src="'+l+'" alt=""><br> Abb.: भुजङ्गः<br> Banded Krait (<em>Bungarus fasciatus</em>)<br> [Bildquelle: J. Ewart. The poisonous snakes of India, 1878. Public domain]</p><p>केवलम् Adv.: nur, allein, vollständig</p><p>विष n.: Gift</p><p><img src="'+h+'" alt=""><br> Abb.: भुजङ्गस्य विषम्<br> Melken von Schlangengift (Krait), Thailand<br> [Bildquelle:  TheLawleys. -- <a href="http://www.flickr.com/photos/lawley/4918566/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/lawley/4918566/</a>. -- Zugriff am 2009-01-03. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p><p>शास् 2P शास्ति : zurechtweisen, beherrschen, befehlen, lehren</p><blockquote><p>hat den schwachen Präsensstamm शिष् : शिष्मस् , die 3.Pl. P. hat aber Starken Stamm: शासति (!! Endung -ati) neben gelegentlich शासन्ति. अशासुर्. Auch das ganze आत्मनेपद hat, soweit es vorkommt, den starken Stamm: शास्ते</p><p>Perf I शशास, शशासुर्<br> Fut. शासिष्यति<br> Pass. -शास्यते । शिष्यते<br> PPP शिष्ट : gelehrt, weise<br> Inf. शासितुम्<br> Absol. -शिष्य । -शास्य</p><p>davon:</p><p>शासना f.: königliches Edikt, Lehre, Religion</p></blockquote><p><img src="'+p+'" alt=""><br> Abb.: शासना<br> Ashoka-Edikt, Dhauli, Orissa<br> [Bildquelle: vegdevil. -- <a href="http://www.flickr.com/photos/vegdevil/915850174/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/vegdevil/915850174/</a>. -- Zugriff am 2009-01-03. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><blockquote><p>शास्त्र n.: Lehre, Lehrwerk</p><p>शास्त्रिन् m.: gelehrt, Gelehrter</p></blockquote><p><img src="'+b+'" alt=""><br> Abb.: शास्त्री<br> Max Müller (1823 - 1900), ca. 1898<br> [Bildquelle: Wikipedia. Public domain]</p><blockquote><p>शिष्य 3: zu belehrender = Schüler</p></blockquote><p>शरण 3: schützend, schirmend ; n. Schutz, Zuflucht, das Zufluchnehmen zu</p><p>सङ्घ n.: (zu सम्-हन् : zusammen-schlagen): Schar, Haufe, Gemeinde (z.B. buddhistische)</p><blockquote><p>s. dazu:</p><blockquote><p><strong>Payer, Alois &lt;1944 - &gt;:</strong> Vinayamukha : Grundbegriffe der Ordensregeln und des Ordensrechts des Theravāda. -- Teil I. -- (Materialien zu den Grundbegriffen des Buddhismus). -- <em>URL</em>: <a href="http://www.payer.de/buddhgrund/vinaya01.htm" target="_blank" rel="noreferrer">http://www.payer.de/buddhgrund/vinaya01.htm</a></p></blockquote></blockquote><p>कन्या f.: junges Mädchen, Tochter, Jungfrau</p><p>अति Präverb: über, über -weg, über - hinaus (im Raum, in der Zeit, an Zahl, an Menge, in der Ordnung, an Macht, an Intensität), überaus</p><p>इ + अति 2P अत्येति : vorübergehen</p><blockquote><p>PPP अतीत : n. Vergangenheit</p></blockquote><h2 id="_41-4-ubung" tabindex="-1">41.4. Übung <a class="header-anchor" href="#_41-4-ubung" aria-label="Permalink to &quot;41.4. Übung&quot;">​</a></h2><p>A) Übersetzen Sie die beiden Sprichwörter am Anfang der Lektion.</p><p>B) Übersetzen Sie:</p><p>बुद्धम् शरणं गच्छामि धर्मं शरणं गच्छामि सङ्घं शरणं गच्छामीति बुद्धगतैर्वक्तव्यम् ॥१॥</p><p>काशीं पत्स्ये गङ्गां द्रक्ष्यामि तत्र च मरिष्यामीति मन्यमानो मान्यो वृद्धनरः पुत्रांश्च पुत्रपुत्रांश्च धनं च तत्याज काशीं च प्राव्रजत् । एवं च रोध्यं दुःखं तरिष्यतीति मन्ये ॥२॥</p><p><img src="'+m+'" alt=""><br> Abb.: काशीं पत्स्ये गङ्गां द्रक्ष्यामि ...<br> [Bildquelle: jpereira_net. -- <a href="http://www.flickr.com/photos/jpereira_net/2914877721/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/jpereira_net/2914877721/</a>. -- Zugriff am 2009-01-04. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine Bearbeitung)]</p><p>कन्यां व्युवह तस्यां च पुत्रमजनयं महाधनं च लेभ एवं सुखमापेत्यतीते मुमोह । ततः प्रजज्ञौ सुखाद्दुःखं जायते तस्माल्लोकसुखमपि त्यजनीयं न च किंचिदिन्द्रियैः स्प्रष्टव्यमिति ॥३॥</p><p>विक्रेयाणि विक्रीयापुत्रवैश्यो भिक्षुभ्यो विक्रयफलमददाद्दानपुण्यं चादत्त । एतत्कर्म स्तुत्यमिति भिक्षवः प्रोचुर्बुद्धिमन्तस्तु विकल्पयन्ति किमेवं कुर्वाणो वश्यः पुण्यं चकारेति ॥४॥</p><p>गुरुभिः शिष्याः शासितव्याः शिष्यैरध्ययनमध्येतव्यम् ॥५॥</p>',122)])])}const _=t(c,[["render",f]]);export{P as __pageData,_ as default};
